examples.after:
// Allowlist of permitted handler classes
private static final Map<String, Class<? extends Handler>> ALLOWED = Map.of(
  "export", ExportHandler.class,
  "import", ImportHandler.class
);

String handlerName = request.getParameter("handler");
Class<? extends Handler> clazz = ALLOWED.get(handlerName);
if (clazz == null) {
  throw new IllegalArgumentException("Unknown handler: " + handlerName);
}
Handler instance = clazz.getDeclaredConstructor().newInstance();
instance.execute();
